// Solution
function solve(input) {
	let stack = [];
	let tags = [];
	for (let i = 0; i < input.length; i++) {
		if (input[i] === '<') {
			let tag = '';
			while (input[i] !== '>') {
				tag += input[i++];
			}
			if (tag[1] === '/') {
				stack.pop();
			} else {
				stack.push(tag);
			}
			tags.push(tag);
		}
	}
	while (stack.length > 0) {
		tags.push('</' + stack.pop() + '>');
	}
	return tags;
}

